import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int maxBufferSize = 10;
        char[] buffer = new char[maxBufferSize]; // Buffer of fixed size

        // Copy user input into buffer after ensuring it fits within the buffer size
        if (userInput.length() > maxBufferSize) {
            System.out.println("Input exceeds buffer size. Truncating input.");
            userInput.getChars(0, maxBufferSize, buffer, 0);
        } else {
            userInput.getChars(0, userInput.length(), buffer, 0);
        }

        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
